input:
let dc_colormap: Uint8Array;
let dc_x: number;
let dc_yl: number;
let dc_yh: number;
let dc_source: Uint8Array;

function R_DrawColumn(): void {
  let count = dc_yh - dc_yl;
  if (count < 0) return;
  let dest = ylookup[dc_yl] + columnofs[dc_x];
  const fracstep = dc_iscale;
  let frac = dc_texturemid + (dc_yl - centery) * fracstep;
  do {
    dest[0] = dc_colormap[dc_source[frac >> FRACBITS]];
    dest += SCREENWIDTH;
    frac += fracstep;
  } while (count--);
}
